using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;

namespace MyApp;

/// <summary>
/// Entity Framework Core の DbContext。
///
/// 定型的な設定は自動生成された <see cref="AutoGeneratedDbContext"/> でなされている。
/// こちらでは必要に応じて拡張やオーバーライドを行う。
/// </summary>
public partial class OverridedDbContext : AutoGeneratedDbContext {
    public OverridedDbContext(DbContextOptions<OverridedDbContext> options, ILogger<OverridedDbContext> logger) : base(options) {
        _logger = logger;
    }

    /// <summary>SQLのログ出力用</summary>
    private readonly ILogger<OverridedDbContext> _logger;

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder) {
        // EFCore が標準で出力するログのうち Information 以上のものを標準のデバッグログとして出力する
        // （EFCore の Information はSQLなどで、 Debug はコネクションの接続や解放などが含まれる）。
        // EFCore 側のログ（"Microsoft.EntityFrameworkCore" カテゴリで出力される）と二重で出力されるので、
        // 必要に応じて EFCore 側のログが出力されないように調整などすること。
        optionsBuilder.LogTo(
            sql => _logger.LogDebug(sql),
            LogLevel.Information,
            Microsoft.EntityFrameworkCore.Diagnostics.DbContextLoggerOptions.SingleLine);
    }

    protected override void ConfigureSequenceMember(
        Microsoft.EntityFrameworkCore.ModelBuilder modelBuilder,
        Microsoft.EntityFrameworkCore.Metadata.Builders.EntityTypeBuilder entity,
        Microsoft.EntityFrameworkCore.Metadata.Builders.PropertyBuilder<int?> property,
        string sequenceName) {

        // SQLite の場合（SQLiteにはシーケンスがないため、AUTO_INCREMENTを使用）
        property.HasAnnotation("Sqlite:Autoincrement", true);
    }
}
